#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 1;

class KernelCa6k00390Custom {
public:
    __aicore__ inline KernelCa6k00390Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t groups,
                                uint32_t channels, uint32_t spatialSize, uint32_t batchSize,
                                uint32_t sampleLen, uint32_t channelsPerGroup)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        groups_ = groups;
        channels_ = channels;
        spatialSize_ = spatialSize;
        batchSize_ = batchSize;
        sampleLen_ = sampleLen;
        channelsPerGroup_ = channelsPerGroup;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t strideElems = blockNum * tileLen_;
        for (uint32_t base = blockIdx * tileLen_; base < totalLen_; base += strideElems)
        {
            uint32_t curLen = totalLen_ - base;
            if (curLen > tileLen_) curLen = tileLen_;
            Compute(base, curLen);
        }
    }

private:
    __aicore__ inline void Compute(uint32_t gmOffset, uint32_t len)
    {
        for (uint32_t i = 0; i < len; ++i)
        {
            uint32_t outIdx = gmOffset + i;
            // compute input index from output index
            uint32_t n = outIdx / sampleLen_;
            uint32_t rem = outIdx % sampleLen_;
            uint32_t cout = rem / spatialSize_;
            uint32_t hw = rem % spatialSize_;
            uint32_t cin = (cout % groups_) * channelsPerGroup_ + (cout / groups_);
            uint32_t inIdx = n * sampleLen_ + cin * spatialSize_ + hw;
            float val = xGm_.GetValue(inIdx);
            yGm_.SetValue(outIdx, val);
        }
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t groups_ {2};
    uint32_t channels_ {0};
    uint32_t spatialSize_ {0};
    uint32_t batchSize_ {0};
    uint32_t sampleLen_ {0};
    uint32_t channelsPerGroup_ {0};
};

extern "C" __global__ __aicore__ void ca6k00390_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00390Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.groups, tiling_data.channels, tiling_data.spatialSize, tiling_data.batchSize,
            tiling_data.sampleLen, tiling_data.channelsPerGroup);
    op.Process();
}
